// Extract body data from webhook
const items = $input.all();
const body = items[0].json;

// Tech comfort mapping for display
const techComfortMap = {
  '1': '1 — I avoid it where I can',
  '2': '2 — I use what I have to',
  '3': '3 — Comfortable with everyday tools',
  '4': '4 — I enjoy learning new tools',
  '5': '5 — I love technology and adopt it early'
};

const techComfortLabel = techComfortMap[body.techComfort?.charAt(0)] || body.techComfort;

return [{
  json: {
    ...body,
    techComfortLabel
  }
}];

// Prepare email content for André
const phone = $json.phone || 'Not provided';
const anythingElse = $json.anythingElse || 'Nothing else shared';
const toolFrustrations = $json.toolFrustrations || 'No frustrations mentioned';
const automationAttempts = $json.automationAttempts || 'No previous attempts';

return [{
  json: {
    ...$json,
    phone,
    anythingElse,
    toolFrustrations,
    automationAttempts
  }
}];

